\toprule
Prescription & $\mu$ (GeV) & $Q(c, b, t)$ & $|Q - 2/3|$ \\
\midrule
$\mu = m_\tau$ (baseline) & $1.77686$ & $0.6667177$ & $5.10 \times 10^{-5}$ \\
$\mu = \sum m_\ell$ (companion-note scale) & $1.88303$ & $0.6674136$ & $7.47 \times 10^{-4}$ \\
$\mu = 2$~GeV (conventional reference) & $2.00000$ & $0.6681029$ & $1.44 \times 10^{-3}$ \\
$\mu = 1.5$~GeV (intermediate) & $1.50000$ & $0.6644741$ & $2.19 \times 10^{-3}$ \\
$\mu = m_c(m_c)$ (charm self-scale) & $1.28070$ & $0.6620198$ & $4.65 \times 10^{-3}$ \\
$\mu = m_b(m_b)$ (bottom self-scale) & $4.20300$ & $0.6746516$ & $7.98 \times 10^{-3}$ \\
$\mu = M_Z$ & $91.18760$ & $0.6878866$ & $2.12 \times 10^{-2}$ \\
$\mu = m_t(m_t)$ (top self-scale) & $162.50000$ & $0.6894162$ & $2.27 \times 10^{-2}$ \\
